UPDATE public.questions SET
  stimulus_text = 'The scientist discovered that while the color of a flower can be perceived by the human eye, the scent of a flower can be detected by the nose. The scientist explained that the sense of smell is more powerful than the sense of sight because the sense of smell can trigger memories and emotions. This theory was supported by a recent study that found that people were more likely to remember a happy memory when they smelled a familiar scent than when they saw a familiar picture. What is the most likely reason why the writer chose to use a semicolon in the sentence, "The scientist explained that the sense of smell is more powerful than the sense of sight; this theory was supported by a recent study that found that people were more likely to remember a happy memory when they smelled a familiar scent than when they saw a familiar picture."',
  question_text = 'The semicolon in the sentence is most likely used to',
  stimulus_type = NULL,
  options = '[{"id":"A","text":"separate two closely related independent clauses.","is_correct":true,"explanation":"Choice A matches the question''s requirement and is consistent with the passage''s central claim or supporting detail. Re-read the sentences surrounding the key detail before eliminating this option on test day."},{"id":"B","text":"introduce a list of items.","is_correct":false,"explanation":"Choice B is incorrect because it either misreads the passage, overgeneralizes a limited detail, or focuses on information irrelevant to the question stem. Re-read the sentences surrounding the key detail before eliminating this option on test day."},{"id":"C","text":"set off a nonessential phrase.","is_correct":false,"explanation":"Choice C is incorrect because it either misreads the passage, overgeneralizes a limited detail, or focuses on information irrelevant to the question stem. Re-read the sentences surrounding the key detail before eliminating this option on test day."},{"id":"D","text":"indicate a pause in the flow of the sentence.","is_correct":false,"explanation":"Choice D is incorrect because it either misreads the passage, overgeneralizes a limited detail, or focuses on information irrelevant to the question stem. Re-read the sentences surrounding the key detail before eliminating this option on test day."}]'::jsonb,
  correct_answer = 'A',
  explanation = 'The semicolon is used to separate two closely related independent clauses. The first independent clause is "The scientist explained that the sense of smell is more powerful than the sense of sight." The second independent clause is "this theory was supported by a recent study that found that people were more likely to remember a happy memory when they smelled a familiar scent than when they saw a familiar picture." The two clauses are related because the second clause provides evidence for the first clause. Semicolons are often used to separate two related independent clauses when a conjunction is not used. The passage states that "The scientist discovered that while the color of a flower can be perceived by the human eye, the scent of a flower can b…", which is the textual anchor for eliminating weaker choices. Choice A is correct because it aligns with that evidence: separate two closely related independent clauses.. Each incorrect option either contradicts a explicit detail, imports information not present in the text, or answers a different question than the one asked.',
  source_metadata = COALESCE(source_metadata, '{}'::jsonb) || '{"section":"english","skill_id":"BOU","domain_id":"conventions","opensat_index":1425,"opensat_domain":"Standard English Conventions","opensat_raw_id":"random_id_a3","opensat_difficulty":"Easy","english_content_v2":true,"english_content_upgraded_at":"2026-06-12T20:01:56.882Z","english_content_upgrade_method":"upgrade-english-content.mjs"}'::jsonb,
